var e=[{id:`L2_1`,type:`dialog`,speaker:`SHIELD_ADMIN_NAMED_NULL`,text:{KOREA:`부전대장님, 방패 뒤에 계십시오! 돌출되면 위험합니다!`,JPN:`副戦隊長殿、盾の後ろに！　体を出しては危険です！`,ENG:`Deputy Commander! Please stay behind the shield! It's too dangerous to go out there by yourself!`,TWN:`副隊長，請躲在盾牌後面，萬一被敵人看到會有危險的！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`SHIELD_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`난 됐고 다른 애들이나 신경 써, 발레리.`,JPN:`私はいいから他の子どもたちを気にかけてあげて、ヴァレリーちゃん。`,ENG:`Don't worry about me and take care of the other kids, Valeriy.`,TWN:`別管我，保護孩子們，瓦萊里。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`보급품 망가지면 골치 아파지잖아. 이 난리통에 어디서 새 걸 구하니?`,JPN:`補給品が壊れると困っちゃうわ。
こんな状況でどこで新品を手に入れればいいのかしら？`,ENG:`We wouldn't want to break any equipment right now. We'd be hard-pressed to get any replacements while everything's so hectic.`,TWN:`萬一補給品損壞就麻煩了，在這種亂戰中是要到哪裡去找新的補給？`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SHIELD_ADMIN_NAMED_NULL`,text:{KOREA:`아니, 이 상황까지 와서 보급품 걱정이십니까?`,JPN:`何と、こんな時に補給品の心配をなさるのですか？`,ENG:`With all due respect, now's not the time to be worried about equipment, ma'am!`,TWN:`不，都這種情況了，妳還擔心補給品？`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`SHIELD_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`당연하지. 네가 들고 있는 방패가 우리 몸값보다 비싼데.`,JPN:`当たり前じゃない。あなたの持っている盾の方が、
私たちの命よりよっぽど高価なの。`,ENG:`Of course it is. Your shield costs more than what we make.`,TWN:`當然了，你手裡的盾牌可比我們的命還要貴。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`그리고 고개 숙여.`,JPN:`あと、頭を下げなさい。`,ENG:`And stay down.`,TWN:`還有，低下頭來。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SHIELD_ADMIN_NAMED_NULL`,text:{KOREA:`감사합니다. 하마터면 침식체 놈에게 뒤통수가 날아갈 뻔했군요.`,JPN:`感謝します。危うく侵食体の野郎に
後頭部をかち割られるところでした。`,ENG:`Thank you. That C.O. almost sliced my head off.`,TWN:`謝謝，我差點就被侵蝕體咬掉頭了。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`SHIELD_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`조심해. 방호복을 입었어도 머리통이 날아가면 죽는 건 마찬가지니까.`,JPN:`気をつけなさいね。防護服を着てても頭が吹っ飛んじゃえば
当然死んじゃうのよ。`,ENG:`Be careful. Even with all that armor, you'll be pretty dead if they blow your head off.`,TWN:`小心點，就算穿著防護服，被爆頭的話一樣會死。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SHIELD_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`그나저나 이상하네, 이 녀석들.`,JPN:`それにしても、こいつらちょっとおかしいわね。`,ENG:`Anyway, what's up with these guys?`,TWN:`不過這些傢伙真奇怪啊。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`이번이 몇 번째 공격이더라? 잡아도 잡아도 줄어들 생각을 안 하네?`,JPN:`今回で何度目の攻撃かしら？
仕留めても仕留めてもキリがないわ。`,ENG:`How many waves have we had now? They just keep coming and coming, don't they?`,TWN:`這已經是第幾波進攻了？不管怎麼打數量都沒有減少耶？`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`SHIELD_ADMIN_NAMED_NULL`,text:{KOREA:`저 빛기둥들이 나타난 뒤로 더 심해졌습니다.`,JPN:`あの光の柱が現れてからさらに酷くなっています。`,ENG:`It seems to be getting worse ever since that pillar of light appeared.`,TWN:`自從那道光柱出現之後，情勢就變得更嚴峻了。`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SHIELD_ADMIN_NAMED_NULL`,text:{KOREA:`최전선에서 무슨 문제가 생긴 것 아닐까요?`,JPN:`最前線で何か起きたのではないでしょうか？`,ENG:`Perhaps something went down at the front lines?`,TWN:`最前線是不是遇到了什麼麻煩？`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`흐음......`,JPN:`ふむ……`,ENG:`Hmm...`,TWN:`嗯……`},stage:{bg:`COUNTERSIDE_RED_ADF`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`부전대장님, 정찰대에서 보고가 들어왔습니다.`,JPN:`副戦隊長殿、偵察隊より報告です。`,ENG:`Deputy Commander, we have reports from the recon team.`,TWN:`副隊長，偵察隊發來了報告。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`말해 봐, 예고르. 좋은 소식이니?`,JPN:`聞かせてちょうだい、イェゴールちゃん。良い知らせかしら？`,ENG:`Spill the beans, Yegor. Is it good news?`,TWN:`說吧，伊高爾，是好消息嗎？`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};